exercise.solution:
const book = {
  title: "Pride and Prejudice",
  author: "Jane Austen",
  pages: 432,
  summary() {
    console.log(this.title + " by " + this.author + " — " + this.pages + " pages.");
  }
};

book.summary();

const { title, author } = book;
console.log(title);
console.log(author);
